import React, { useState } from 'react';
import axios from 'axios';
import MapDisplay from './components/MapDisplay';
import SafetyIndicators from './components/SafetyIndicators';
import SOSButton from './components/SOSButton';
import './App.css';
import { MapPinIcon, MagnifyingGlassIcon } from '@heroicons/react/24/solid';

function App() {
  const [source, setSource] = useState('');
  const [destination, setDestination] = useState('');
  const [loading, setLoading] = useState(false);
  const [routeFound, setRouteFound] = useState(false);

  // ... (keep your geocode and handleFindRoute logic same as before)

  return (
    <div style={{ position: 'relative', height: '100vh', width: '100vw', overflow: 'hidden', backgroundColor: '#111' }}>
      
      {/* Background Map */}
      <div style={{ position: 'absolute', inset: 0, zIndex: 0 }}>
         <MapDisplay waypoints={[]} /> 
      </div>

      {/* Floating Search Card */}
      <div style={{ 
        position: 'absolute', top: '20px', left: '20px', zIndex: 10,
        width: '320px', backgroundColor: 'rgba(255, 255, 255, 0.95)',
        padding: '20px', borderRadius: '16px', boxShadow: '0 10px 25px rgba(0,0,0,0.2)'
      }}>
        
        {/* Compact Header */}
        <div style={{ display: 'flex', alignItems: 'center', marginBottom: '15px' }}>
          <img src="/Logo.jpeg" alt="S" style={{ height: '35px', width: '35px', borderRadius: '50%', marginRight: '10px' }} />
          <h1 style={{ fontSize: '18px', fontWeight: '800', margin: 0 }}>SheRoute</h1>
        </div>

        <div style={{ display: 'flex', flexDirection: 'column', gap: '10px' }}>
          
          {/* Start Point Input */}
          <div style={{ position: 'relative' }}>
            <MapPinIcon style={{ position: 'absolute', left: '10px', top: '10px', height: '16px', width: '16px', color: '#999' }} />
            <input
              type="text"
              placeholder="Start point..."
              value={source}
              onChange={(e) => setSource(e.target.value)}
              style={{ width: '100%', padding: '8px 10px 8px 35px', borderRadius: '8px', border: '1px solid #ddd', fontSize: '13px' }}
            />
          </div>

          {/* Destination Input */}
          <div style={{ position: 'relative' }}>
            <MapPinIcon style={{ position: 'absolute', left: '10px', top: '10px', height: '16px', width: '16px', color: '#ec4899' }} />
            <input
              type="text"
              placeholder="Destination..."
              value={destination}
              onChange={(e) => setDestination(e.target.value)}
              style={{ width: '100%', padding: '8px 10px 8px 35px', borderRadius: '8px', border: '1px solid #ddd', fontSize: '13px' }}
            />
          </div>

          <button
            style={{ 
              width: '100%', padding: '10px', backgroundColor: '#000', color: '#fff', 
              borderRadius: '8px', fontWeight: 'bold', cursor: 'pointer', border: 'none',
              display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '8px'
            }}
          >
            <MagnifyingGlassIcon style={{ height: '14px', width: '14px' }} />
            FIND SAFE ROUTE
          </button>
        </div>
      </div>

      <SOSButton />
    </div>
  );
}

export default App;
